mapper.update:
UPDATE price_alert_config
threshold_percent = #{thresholdPercent}, enable_status = #{enableStatus}, remark = #{remark}, update_time = NOW()
WHERE config_id = #{configId}

mapper.select:
SELECT pal.alert_id AS alertId, pal.drug_id AS drugId, pal.alert_type AS alertType, pal.alert_level AS alertLevel, pal.alert_content AS alertContent, pal.current_purchase_price AS currentPurchasePrice, pal.current_retail_price AS currentRetailPrice, pal.threshold_percent AS thresholdPercent, pal.handle_status AS handleStatus, pal.handler, pal.handle_time AS handleTime, pal.handle_remark AS handleRemark, pal.create_time AS createTime, d.drug_name AS drugName, d.specification FROM price_alert_log pal INNER JOIN drug_info d ON pal.drug_id = d.drug_id WHERE 1=1
AND pal.drug_id = #{drugId}
AND pal.alert_type = #{alertType}
AND pal.handle_status = #{handleStatus}
AND DATE(pal.create_time) >= #{startDate}
AND DATE(pal.create_time) <= #{endDate}
ORDER BY pal.create_time DESC
